/* ─── Reset & Base ──────────────────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font: 'Inter', system-ui, -apple-system, sans-serif;
  --bg: #000;
  --surface: #111;
  --surface-2: #1a1a1a;
  --border: #222;
  --text: #ffffff;
  --text-muted: #666;
  --blue: #3b82f6;
  --amber: #f59e0b;
  --green: #10b981;
  --pink: #ec4899;
  --header-height: 60px;
}

html, body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  height: 100%;
  overflow: hidden;
}

#root {
  height: 100%;
}

button {
  font-family: var(--font);
  cursor: pointer;
}

select {
  font-family: var(--font);
  appearance: none;
  cursor: pointer;
}

/* ─── Dashboard Layout ─────────────────────────────────────────────────── */
.dashboard {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  background: var(--bg);
}

.dashboard__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px;
  background: var(--bg);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  gap: 10px;
}

.dashboard__header-left {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}

.dashboard__header-right {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
}

.dashboard__title {
  font-size: 1.05rem;
  font-weight: 900;
  letter-spacing: 0.14em;
  color: var(--text);
  white-space: nowrap;
}

.dashboard__profile-trigger {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 6px 10px;
  border-radius: 8px;
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 5px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 160px;
}

