  background: var(--surface);
  border: 1px solid var(--border);
  padding: 6px 10px;
  border-radius: 8px;
  font-size: 0.8rem;
  font-weight: 700;
  white-space: nowrap;
}

.dashboard__icon-btn {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  width: 34px;
  height: 34px;
  border-radius: 8px;
  font-size: 1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  flex-shrink: 0;
}

.dashboard__main {
  flex: 1;
  overflow-y: auto;
  padding: 14px;
  -webkit-overflow-scrolling: touch;
}

.dashboard__view-toggle {
  display: flex;
  gap: 8px;
  margin-bottom: 14px;
}

/* ─── Buttons ───────────────────────────────────────────────────────────── */
.btn-review {
  display: block;
  width: 100%;
  margin-bottom: 12px;
  padding: 13px 20px;
  background: var(--blue);
  color: white;
  border: none;
  border-radius: 10px;
  font-weight: 800;
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  cursor: pointer;
  transition: opacity 0.15s;
}

.btn-review:hover { opacity: 0.9; }
.btn-review:disabled { opacity: 0.4; cursor: not-allowed; }

.btn-toggle {
  flex: 1;
  padding: 9px 12px;
  background: var(--surface);
  color: #888;
  border: 1px solid var(--border);
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.72rem;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: all 0.15s;
}

.btn-toggle:hover { border-color: #444; color: #ccc; }

.btn-toggle.active {
  background: white;
  color: #000;
  border-color: white;
}

/* ─── Section Titles ────────────────────────────────────────────────────── */
.section-title {
  font-size: 0.68rem;
  font-weight: 800;
  letter-spacing: 0.12em;
  color: var(--text-muted);
  text-transform: uppercase;
}

/* ─── Mastery Grid ──────────────────────────────────────────────────────── */
.mastery-grid-container {
  position: relative;
  padding-bottom: 80px;
}

.grid-toolbar {
  display: flex;
  gap: 8px;
  margin-bottom: 12px;
}

.sort-select {
  flex: 1;
  padding: 8px 12px;
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 8px;
  font-size: 0.82rem;
  width: auto;
}

.mastery-grid__cards {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
  gap: 7px;
}

.grid-item-wrapper {
  transition: opacity 0.2s;
}

/* ─── Vocab Cards ───────────────────────────────────────────────────────── */
.vocab-card {
  padding: 10px 9px;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: var(--surface);
  user-select: none;
  cursor: pointer;
  position: relative;
  overflow: visible;
}

.vocab-card--not_started  { border-color: #374151; background: #080808; }
.vocab-card--introduced   { border-color: #1d4ed8; background: #0c1a3a; }
.vocab-card--practicing   { border-color: #92400e; background: #1a1000; }
.vocab-card--confident    { border-color: #16a34a; background: #001a0a; }
.vocab-card--mastered     { border-color: #22c55e; background: #002010; }

.vocab-card__word {
  font-weight: 700;
  font-size: 0.88rem;
  color: var(--text);
  margin-bottom: 3px;
  word-break: break-word;
