.builder-panel {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  z-index: 500;
  padding: 14px 16px;
  background: rgba(10, 10, 10, 0.97);
  border-top: 1px solid #333;
  backdrop-filter: blur(10px);
}

.builder-content {
  max-width: 600px;
  margin: 0 auto;
}

.suggestion-pill {
  background: var(--surface-2);
  border: 1px solid #333;
  color: #bbb;
  padding: 5px 12px;
  border-radius: 20px;
  font-size: 0.78rem;
  cursor: pointer;
  transition: all 0.15s;
  font-family: var(--font);
}

.suggestion-pill:hover { background: #2a2a2a; color: white; border-color: #555; }

/* ─── Phrase Grid ───────────────────────────────────────────────────────── */
.phrase-grid {
  padding-bottom: 20px;
}

/* ─── Drawer Backdrop ───────────────────────────────────────────────────── */
.drawer-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.75);
  z-index: 1000;
}

/* ─── Word Detail Drawer ────────────────────────────────────────────────── */
.word-drawer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  max-height: 80vh;
  background: var(--surface);
  border-top-left-radius: 20px;
  border-top-right-radius: 20px;
  z-index: 1001;
  display: flex;
  flex-direction: column;
  color: var(--text);
  overflow: hidden;
}

.drawer__handle {
  width: 40px;
  height: 4px;
  background: #333;
  border-radius: 2px;
  margin: 12px auto 6px;
  flex-shrink: 0;
}

.drawer__scroll-area {
  flex: 1;
  overflow-y: auto;
  padding: 12px 20px 20px;
}

/* ─── Profile Drawer ────────────────────────────────────────────────────── */
.profile-drawer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  max-height: 82vh;
  background: var(--surface);
  border-top-left-radius: 20px;
  border-top-right-radius: 20px;
  z-index: 1001;
  overflow-y: auto;
  color: var(--text);
}

/* ─── Settings Drawer ───────────────────────────────────────────────────── */
.settings-drawer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  max-height: 85vh;
  background: var(--surface);
  border-top-left-radius: 20px;
  border-top-right-radius: 20px;
  z-index: 1001;
  overflow-y: auto;
  color: var(--text);
}

/* ─── Chat Drawer ───────────────────────────────────────────────────────── */
.chat-drawer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 92vh;
  background: var(--surface);
  border-top-left-radius: 20px;
  border-top-right-radius: 20px;
  z-index: 2000;
  display: flex;
  flex-direction: column;
  color: var(--text);
  touch-action: none;
}

/* ─── Settings Drawer Controls ──────────────────────────────────────────── */
.settings-section {
  background: var(--surface-2);
  padding: 14px;
  border-radius: 10px;
  margin-bottom: 10px;
}

.settings-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: white;
  cursor: pointer;
}

.settings-label {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: #888;
  text-transform: uppercase;
  display: block;
}

.settings-checkbox {
  width: 20px;
  height: 20px;
  cursor: pointer;
  accent-color: var(--blue);
}

.settings-input {
  width: 100%;
  padding: 10px 12px;
  background: #000;
  border: 1px solid var(--border);
  color: white;
  border-radius: 8px;
  margin-bottom: 10px;
  font-size: 0.9rem;
  font-family: var(--font);
  outline: none;
  box-sizing: border-box;
}

.settings-input:focus {
  border-color: var(--blue);
}

.btn-settings {
  display: block;
  width: 100%;
  padding: 11px;
  background: var(--blue);
  color: white;
  border: none;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  cursor: pointer;
}

/* ─── Danger Zone ───────────────────────────────────────────────────────── */
.danger-zone {
  border: 1px solid #3f0a0a;
  padding: 16px;
  border-radius: 12px;
  margin-top: 24px;
  background: #0f0000;
}

.btn-danger {
  display: block;
  width: 100%;
  padding: 11px;
  background: transparent;
  color: #ef4444;
  border: 1px solid #7f1d1d;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.78rem;
  letter-spacing: 0.05em;
  cursor: pointer;
  text-align: left;
  transition: background 0.15s;
}

.btn-danger:hover { background: #1f0000; }

/* ─── Progress Bar ──────────────────────────────────────────────────────── */
.progress-bar-track {
  height: 6px;
  background: #1a1a1a;
  border-radius: 3px;
  overflow: hidden;
}

.progress-bar-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.4s ease;
}

/* ─── Scrollbars ────────────────────────────────────────────────────────── */
::-webkit-scrollbar { width: 3px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 4px; }

/* ─── Misc ──────────────────────────────────────────────────────────────── */
button:active { transform: scale(0.97); }

